      if (walletType !== 'affiliate') {
        const rolloverRequired = parseFloat(user.rolloverRequired || '0');
        const rolloverCompleted = parseFloat(user.rolloverCompleted || '0');
        const rolloverRemaining = rolloverRequired - rolloverCompleted;

