    font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Roboto', sans-serif;
  }

  h1, h2, h3, h4, h5, h6 {
    font-family: 'Poppins', 'Inter', sans-serif;
  }
}

@layer utilities {
  .hover-elevate {
    @apply transition-all duration-200;
    @apply hover:brightness-110;
  }

  .active-elevate-2 {
    @apply transition-all duration-100;
    @apply active:brightness-125;
  }

  .no-default-hover-elevate {
    @apply hover:brightness-100 hover:saturate-100;
  }

  .no-default-active-elevate {
    @apply active:brightness-100 active:saturate-100;
  }

  .toggle-elevate {
    @apply transition-all duration-200;
  }

  .toggle-elevated {
    @apply brightness-125 saturate-125;
  }
}

/* Casino Background Pattern - Cobertura Total */
.casino-bg {
  background: url('/fundo.png') no-repeat center center fixed;
  background-size: cover;
  background-color: #012606;
  position: relative;
}

/* Background com blur para profundidade */
.casino-bg::before {
  content: '';
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  z-index: 1;
  background-image: url('/fundo.png');
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
  filter: blur(12px);
  transform: scale(1.1);
}

/* Overlay escuro por cima do blur */
.casino-bg::after {
  content: '';
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  z-index: 1;
  background: rgba(0, 0, 0, 0.5);
}

/* Container do jogo - Sem max-width para ocupar tela inteira */
#game-container {
  width: 100%;
  height: 100vh;
  position: relative;
  overflow: hidden;
}

/* Responsividade - Tamanho da Roleta */
.roulette-container {
  width: min(90vw, 450px);
  aspect-ratio: 1 / 1;
}

@media (max-width: 768px) {
  /* Mobile: roleta ocupa 50% da altura da tela */
  .roulette-container {
    height: 50vh;
    width: auto;
    max-width: 90vw;
  }

  /* Ajuste do background mobile para evitar cortes */
  .casino-bg::before {
    transform: scale(1.05);
  }
}

@media (min-width: 769px) {
  /* Desktop: roleta ocupa 45% da altura da tela */
  .roulette-container {
    height: 45vh;
    width: auto;
    max-width: 90vw;
  }
}

/* Dragon Scale Pattern */
.dragon-scales {
  background-image: 
    repeating-linear-gradient(
      45deg,
      transparent,
      transparent 10px,
      rgba(34, 197, 94, 0.1) 10px,
      rgba(34, 197, 94, 0.1) 20px
    ),
    repeating-linear-gradient(
      -45deg,
      transparent,
      transparent 10px,
      rgba(34, 197, 94, 0.05) 10px,
      rgba(34, 197, 94, 0.05) 20px
    );
}

/* Animation for recent winners slide in */
@keyframes slideInLeft {
  from {
    opacity: 0;
    transform: translateX(-100%);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

.animate-slide-in {
  animation: slideInLeft 0.5s ease-out;
}

