"use client"

import * as React from "react"
import * as SheetPrimitive from "@radix-ui/react-dialog"
import { cva, type VariantProps } from "class-variance-authority"
import { X } from "lucide-react"

import { cn } from "@/lib/utils"

const Sheet = SheetPrimitive.Root

const SheetTrigger = SheetPrimitive.Trigger

const SheetClose = SheetPrimitive.Close

const SheetPortal = SheetPrimitive.Portal

const SheetOverlay = React.forwardRef<
  React.ElementRef<typeof SheetPrimitive.Overlay>,
  React.ComponentPropsWithoutRef<typeof SheetPrimitive.Overlay>
>(({ className, ...props }, ref) => (
  <SheetPrimitive.Overlay
    className={cn(
      "fixed inset-0 z-50 bg-black/80  data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0",
      className
    )}
    {...props}
    ref={ref}
  />
))
SheetOverlay.displayName = SheetPrimitive.Overlay.displayName

const sheetVariants = cva(
  "fixed z-50 gap-4 bg-background p-6 shadow-lg transition ease-in-out data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:duration-300 data-[state=open]:duration-500",
  {
    variants: {
      side: {
        top: "inset-x-0 top-0 border-b data-[state=closed]:slide-out-to-top data-[state=open]:slide-in-from-top",
        bottom:
          "inset-x-0 bottom-0 border-t data-[state=closed]:slide-out-to-bottom data-[state=open]:slide-in-from-bottom",
        left: "inset-y-0 left-0 h-full w-3/4 border-r data-[state=closed]:slide-out-to-left data-[state=open]:slide-in-from-left sm:max-w-sm",
        right:
          "inset-y-0 right-0 h-full w-3/4  border-l data-[state=closed]:slide-out-to-right data-[state=open]:slide-in-from-right sm:max-w-sm",
      },
    },
    defaultVariants: {
      side: "right",
    },
  }
)

interface SheetContentProps
  extends React.ComponentPropsWithoutRef<typeof SheetPrimitive.Content>,
    VariantProps<typeof sheetVariants> {}

const SheetContent = React.forwardRef<
  React.ElementRef<typeof SheetPrimitive.Content>,
  SheetContentProps
>(({ side = "right", className, children, ...props }, ref) => (
  <SheetPortal>
    <SheetOverlay />
    <SheetPrimitive.Content
      ref={ref}
      className={cn(sheetVariants({ side }), className)}
      {...props}
    >
      {children}
      <SheetPrimitive.Close className="absolute right-4 top-4 rounded-sm opacity-70 ring-offset-background transition-opacity hover:opacity-100 focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 disabled:pointer-events-none data-[state=open]:bg-secondary">
        <X className="h-4 w-4" />
        <span className="sr-only">Close</span>
      </SheetPrimitive.Close>
    </SheetPrimitive.Content>
  </SheetPortal>
))
SheetContent.displayName = SheetPrimitive.Content.displayName

const SheetHeader = ({
  className,
  ...props
}: React.HTMLAttributes<HTMLDivElement>) => (
  <div
    className={cn(
      "flex flex-col space-y-2 text-center sm:text-left",
      className
    )}
    {...props}
  />
)
SheetHeader.displayName = "SheetHeader"

const SheetFooter = ({
  className,
  ...props
}: React.HTMLAttributes<HTMLDivElement>) => (
  <div
    className={cn(
      "flex flex-col-reverse sm:flex-row sm:justify-end sm:space-x-2",
      className
    )}
    {...props}
  />
)
SheetFooter.displayName = "SheetFooter"

const SheetTitle = React.forwardRef<
  React.ElementRef<typeof SheetPrimitive.Title>,
  React.ComponentPropsWithoutRef<typeof SheetPrimitive.Title>
>(({ className, ...props }, ref) => (
  <SheetPrimitive.Title
    ref={ref}
    className={cn("text-lg font-semibold text-foreground", className)}
    {...props}
  />
))
SheetTitle.displayName = SheetPrimitive.Title.displayName

const SheetDescription = React.forwardRef<
  React.ElementRef<typeof SheetPrimitive.Description>,
  React.ComponentPropsWithoutRef<typeof SheetPrimitive.Description>
>(({ className, ...props }, ref) => (
  <SheetPrimitive.Description
    ref={ref}
    className={cn("text-sm text-muted-foreground", className)}
    {...props}
  />
))
SheetDescription.displayName = SheetPrimitive.Description.displayName

export {
  Sheet,
  SheetPortal,
  SheetOverlay,
  SheetTrigger,
  SheetClose,
  SheetContent,
  SheetHeader,
  SheetFooter,
  SheetTitle,
  SheetDescription,
}

client/src/pages/AdminDashboard.tsx.content:
import { useAuth } from "@/hooks/useAuth";
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { 
  Users, 
  DollarSign, 
  TrendingUp, 
  TrendingDown,
  UserPlus,
  Wallet,
  ArrowDownToLine,
  Settings as SettingsIcon,
  ChevronDown,
  Dices,
  Calendar
} from "lucide-react";
import { useLocation } from "wouter";
import { useEffect, useState } from "react";
import { cn } from "@/lib/utils";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { 
  LineChart, 
  Line, 
  AreaChart, 
  Area, 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  Legend
} from 'recharts';

// Admin components
import { RouletteSettings } from "@/components/admin/RouletteSettings";
import { UsersManagement } from "@/components/admin/UsersManagement";
import { TransactionsManagement } from "@/components/admin/TransactionsManagement";
import { WithdrawalsManagement } from "@/components/admin/WithdrawalsManagement";
import { GeneralSettings } from "@/components/admin/GeneralSettings";
import { AffiliatesManagement } from "@/components/admin/AffiliatesManagement";

interface DashboardStats {
  totalUsers: number;
  totalDeposits: string;
  totalBets: string;
  totalWinnings: string;
  platformProfit: string;
  activeGames: number;
  pendingWithdrawals: number;
  accountBalance: string;
  todayDeposits: string;
  confirmedDeposits: number;
  paidWithdrawals: string;
}

interface ChartData {
  date: string;
  deposits: number;
  withdrawals: number;
  profit: number;
  newUsers: number;
}

type Section = 'dashboard' | 'users' | 'affiliates' | 'deposits' | 'withdrawals' | 'roulette' | 'system' | 'general-settings';

export default function AdminDashboard() {
  const { user, isAdmin, isLoading } = useAuth();
  const [, setLocation] = useLocation();
  const [activeSection, setActiveSection] = useState<Section>('dashboard');
  const [gestaoOpen, setGestaoOpen] = useState(true);
  const [jogosOpen, setJogosOpen] = useState(true);
  const [sistemaOpen, setSistemaOpen] = useState(false);
  const [password, setPassword] = useState('');
  const [loginError, setLoginError] = useState('');
  const [isLoggingIn, setIsLoggingIn] = useState(false);
  const [dayFilter, setDayFilter] = useState<string>('7');

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError('');
    setIsLoggingIn(true);

    try {
      const response = await fetch('/api/admin/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ password })
      });

      if (response.ok) {
        const { token } = await response.json();
        localStorage.setItem('adminToken', token);
        window.location.reload(); // Recarrega para aplicar o token
      } else {
        setLoginError('Senha incorreta');
      }
    } catch (error) {
      setLoginError('Erro ao fazer login');
    } finally {
      setIsLoggingIn(false);
    }
  };

  const { data: stats } = useQuery<DashboardStats>({
    queryKey: ['/api/admin/stats'],
    enabled: isAdmin,
  });

  const { data: chartData } = useQuery<ChartData[]>({
    queryKey: ['/api/admin/chart-data', dayFilter],
    queryFn: async () => {
      const response = await fetch(`/api/admin/chart-data?days=${dayFilter}`, {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('adminToken')}`,
        },
      });
      if (!response.ok) throw new Error('Failed to fetch chart data');
      return response.json();
    },
    enabled: isAdmin,
  });

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-background">
        <p className="text-muted-foreground">Carregando...</p>
      </div>
    );
  }

  // Show login page if not admin
  if (!isAdmin) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-background">
        <Card className="w-full max-w-md">
          <CardHeader>
            <CardTitle className="text-2xl text-center">Admin Login</CardTitle>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleLogin} className="space-y-4">
              <div className="space-y-2">
                <label htmlFor="password" className="text-sm font-medium">
                  Senha de Administrador
                </label>
                <input
                  id="password"
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full px-3 py-2 border border-border rounded-md bg-background"
                  placeholder="Digite a senha"
                  required
                  data-testid="input-admin-password"
                />
              </div>
              {loginError && (
                <p className="text-sm text-destructive">{loginError}</p>
              )}
              <Button 
                type="submit" 
                className="w-full" 
                disabled={isLoggingIn}
                data-testid="button-admin-login"
              >
                {isLoggingIn ? 'Entrando...' : 'Entrar'}
              </Button>
              <Button 
                type="button" 
                variant="ghost" 
                className="w-full" 
                onClick={() => window.location.href = '/'}
                data-testid="button-back-to-game"
              >
                Voltar ao Jogo
              </Button>
            </form>
          </CardContent>
        </Card>
      </div>
    );
  }

  const MenuItem = ({ 
    icon: Icon, 
    label, 
    section, 
    testId 
  }: { 
    icon: any; 
    label: string; 
    section: Section; 
    testId: string;
  }) => (
    <button
      onClick={() => setActiveSection(section)}
      data-testid={testId}
      className={cn(
        "w-full flex items-center gap-3 px-4 py-2.5 text-sm transition-colors rounded-lg",
        activeSection === section 
          ? "bg-primary text-primary-foreground" 
          : "text-muted-foreground hover:bg-accent hover:text-accent-foreground"
      )}
    >
      <Icon className="h-4 w-4" />
      {label}
    </button>
  );

  const SectionHeader = ({ 
    label, 
    isOpen, 
    onToggle 
  }: { 
    label: string; 
    isOpen: boolean; 
    onToggle: () => void;
  }) => (
    <button
      onClick={onToggle}
      className="w-full flex items-center justify-between px-4 py-2 text-xs font-semibold text-muted-foreground uppercase tracking-wider hover:text-foreground transition-colors"
    >
      {label}
      <ChevronDown className={cn(
        "h-4 w-4 transition-transform",
        isOpen && "transform rotate-180"
      )} />
    </button>
  );

  return (
    <div className="flex h-screen bg-background overflow-hidden">
      {/* Sidebar */}
      <aside className="w-64 border-r border-border bg-card flex flex-col flex-shrink-0">
        {/* Logo */}
        <div className="p-6 border-b border-border">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-primary flex items-center justify-center">
              <Dices className="h-5 w-5 text-primary-foreground" />
            </div>
            <span className="font-display font-bold text-lg">Roleta CashGiro</span>
          </div>
        </div>

        {/* Navigation */}
        <nav className="flex-1 overflow-y-auto p-4 space-y-1">
          <MenuItem 
            icon={SettingsIcon} 
            label="Dashboard" 
            section="dashboard" 
            testId="menu-dashboard"
          />

          <div className="pt-4">
            <SectionHeader 
              label="GESTÃO" 
              isOpen={gestaoOpen} 
              onToggle={() => setGestaoOpen(!gestaoOpen)}
            />
            {gestaoOpen && (
              <div className="mt-1 space-y-1">
                <MenuItem 
                  icon={Users} 
                  label="Usuários" 
                  section="users" 
                  testId="menu-users"
                />
                <MenuItem 
                  icon={UserPlus} 
                  label="Afiliados" 
                  section="affiliates" 
                  testId="menu-affiliates"
                />
                <MenuItem 
                  icon={Wallet} 
                  label="Depósitos" 
                  section="deposits" 
                  testId="menu-deposits"
                />
                <MenuItem 
                  icon={ArrowDownToLine} 
                  label="Saques" 
                  section="withdrawals" 
                  testId="menu-withdrawals"
                />
              </div>
            )}
          </div>

          <div className="pt-4">
            <SectionHeader 
              label="JOGOS" 
              isOpen={jogosOpen} 
              onToggle={() => setJogosOpen(!jogosOpen)}
            />
            {jogosOpen && (
              <div className="mt-1 space-y-1">
                <MenuItem 
                  icon={Dices} 
                  label="Roleta" 
                  section="roulette" 
                  testId="menu-roulette"
                />
              </div>
            )}
          </div>

          <div className="pt-4">
            <SectionHeader 
              label="SISTEMA" 
              isOpen={sistemaOpen} 
              onToggle={() => setSistemaOpen(!sistemaOpen)}
            />
            {sistemaOpen && (
              <div className="mt-1 space-y-1">
                <MenuItem 
                  icon={SettingsIcon} 
                  label="Configurações" 
                  section="general-settings" 
                  testId="menu-settings"
                />
              </div>
            )}
          </div>
        </nav>

        {/* User Info + Logout */}
        <div className="p-4 border-t border-border">
          <Button
            variant="ghost"
            size="sm"
            onClick={() => {
              localStorage.removeItem('adminToken');
              setLocation('/admin');
            }}
            className="w-full justify-start"
            data-testid="button-logout"
          >
            <span className="text-sm">Sair</span>
          </Button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto">
        {/* Header */}
        <header className="border-b border-border bg-card sticky top-0 z-10">
          <div className="px-6 py-4 flex items-center justify-between">
            <div>
              <h1 className="text-2xl font-display font-bold">Dashboard</h1>
              {activeSection === 'dashboard' && (
                <p className="text-sm text-muted-foreground">
                  Olá, Santzim!
                </p>
              )}
            </div>
            <div className="flex items-center gap-2">
              <div className="flex items-center gap-2 text-sm">
                <div className="w-2 h-2 bg-green-500 rounded-full"></div>
                <span className="text-muted-foreground">Usuários Online: 1</span>
              </div>
              <div className="w-8 h-8 rounded-full bg-primary text-primary-foreground flex items-center justify-center font-semibold">
                SZ
              </div>
            </div>
          </div>
        </header>

        {/* Content */}
        <div className="p-6">
          {activeSection === 'dashboard' && (
            <>
              <div className="flex flex-wrap items-center justify-between gap-4 mb-6">
                <p className="text-muted-foreground">
                  Aqui está um resumo das principais métricas do sistema
                </p>
                <div className="flex items-center gap-2">
                  <Calendar className="h-4 w-4 text-muted-foreground" />
                  <Select value={dayFilter} onValueChange={setDayFilter}>
                    <SelectTrigger className="w-40" data-testid="select-day-filter">
                      <SelectValue placeholder="Período" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="7">Últimos 7 dias</SelectItem>
                      <SelectItem value="15">Últimos 15 dias</SelectItem>
                      <SelectItem value="30">Últimos 30 dias</SelectItem>
                      <SelectItem value="90">Últimos 90 dias</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>

              {/* Stats Cards */}
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
                <Card>
                  <CardHeader className="pb-2">
                    <CardTitle className="text-sm font-medium">Lucro do Jogo</CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="text-2xl font-display font-bold" data-testid="text-profit">
                      R$ {stats?.platformProfit || '0,00'}
                    </div>
                  </CardContent>
                </Card>

                <Card>
                  <CardHeader className="pb-2">
                    <CardTitle className="text-sm font-medium">Total Apostado (Jogo)</CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="text-2xl font-display font-bold" data-testid="text-total-bets">
                      R$ {stats?.totalBets || '0,00'}
                    </div>
                  </CardContent>
                </Card>

                <Card>
                  <CardHeader className="pb-2">
                    <div className="flex items-center justify-between">
                      <CardTitle className="text-sm font-medium">Depósitos de Hoje</CardTitle>
                      <span className="text-xs text-muted-foreground">0%</span>
                    </div>
                  </CardHeader>
                  <CardContent>
                    <div className="text-2xl font-display font-bold" data-testid="text-today-deposits">
                      R$ {stats?.todayDeposits || '0,00'}
                    </div>
                  </CardContent>
                </Card>

                <Card>
                  <CardHeader className="pb-2">
                    <CardTitle className="text-sm font-medium">Prêmios Pagos (Jogo)</CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="text-2xl font-display font-bold" data-testid="text-winnings">
                      R$ {stats?.totalWinnings || '0,00'}
                    </div>
                  </CardContent>
                </Card>

                <Card>
                  <CardHeader className="pb-2">
                    <div className="flex items-center justify-between">
                      <CardTitle className="text-sm font-medium">Total de Usuários</CardTitle>
                      <span className="text-xs text-green-500 flex items-center gap-1">
                        <TrendingUp className="h-3 w-3" />
                        100%
                      </span>
                    </div>
                  </CardHeader>
                  <CardContent>
                    <div className="text-2xl font-display font-bold" data-testid="text-users">
                      {stats?.totalUsers || 0}
                    </div>
                  </CardContent>
                </Card>

                <Card>
                  <CardHeader className="pb-2">
                    <CardTitle className="text-sm font-medium">Depósitos Confirmados</CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="text-2xl font-display font-bold" data-testid="text-confirmed-deposits">
                      {stats?.confirmedDeposits || 0}
                    </div>
                  </CardContent>
                </Card>

                <Card>
                  <CardHeader className="pb-2">
                    <CardTitle className="text-sm font-medium">Saldo Total em Contas</CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="text-2xl font-display font-bold" data-testid="text-account-balance">
                      R$ {stats?.accountBalance || '0,00'}
                    </div>
                  </CardContent>
                </Card>

                <Card>
                  <CardHeader className="pb-2">
                    <div className="flex items-center justify-between">
                      <CardTitle className="text-sm font-medium">Saques Pagos</CardTitle>
                      <span className="text-xs text-muted-foreground">0 pendentes</span>
                    </div>
                  </CardHeader>
                  <CardContent>
                    <div className="text-2xl font-display font-bold" data-testid="text-paid-withdrawals">
                      R$ {stats?.paidWithdrawals || '0,00'}
                    </div>
                  </CardContent>
                </Card>
              </div>

              {/* Charts */}
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6">
                {/* Deposits and Withdrawals Chart */}
                <Card>
                  <CardHeader>
                    <CardTitle className="text-base font-medium">Depósitos e Saques</CardTitle>
                  </CardHeader>
                  <CardContent>
                    <ResponsiveContainer width="100%" height={300}>
                      <AreaChart data={chartData || []}>
                        <defs>
                          <linearGradient id="colorDeposits" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="hsl(var(--primary))" stopOpacity={0.8}/>
                            <stop offset="95%" stopColor="hsl(var(--primary))" stopOpacity={0}/>
                          </linearGradient>
                          <linearGradient id="colorWithdrawals" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="hsl(var(--destructive))" stopOpacity={0.8}/>
                            <stop offset="95%" stopColor="hsl(var(--destructive))" stopOpacity={0}/>
                          </linearGradient>
                        </defs>
                        <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                        <XAxis 
                          dataKey="date" 
                          stroke="hsl(var(--muted-foreground))"
                          tick={{ fill: 'hsl(var(--muted-foreground))' }}
                        />
                        <YAxis 
                          stroke="hsl(var(--muted-foreground))"
                          tick={{ fill: 'hsl(var(--muted-foreground))' }}
                        />
                        <Tooltip 
                          contentStyle={{ 
                            backgroundColor: 'hsl(var(--card))', 
                            border: '1px solid hsl(var(--border))',
                            borderRadius: '8px'
                          }}
                          formatter={(value: any) => `R$ ${Number(value).toFixed(2)}`}
                        />
                        <Legend />
                        <Area 
                          type="monotone" 
                          dataKey="deposits" 
                          name="Depósitos"
                          stroke="hsl(var(--primary))" 
                          fillOpacity={1} 
                          fill="url(#colorDeposits)" 
                        />
                        <Area 
                          type="monotone" 
                          dataKey="withdrawals" 
                          name="Saques"
                          stroke="hsl(var(--destructive))" 
                          fillOpacity={1} 
                          fill="url(#colorWithdrawals)" 
                        />
                      </AreaChart>
                    </ResponsiveContainer>
                  </CardContent>
                </Card>

                {/* Profit Chart */}
                <Card>
                  <CardHeader>
                    <CardTitle className="text-base font-medium">Lucro da Plataforma</CardTitle>
                  </CardHeader>
                  <CardContent>
                    <ResponsiveContainer width="100%" height={300}>
                      <LineChart data={chartData || []}>
                        <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                        <XAxis 
                          dataKey="date" 
                          stroke="hsl(var(--muted-foreground))"
                          tick={{ fill: 'hsl(var(--muted-foreground))' }}
                        />
                        <YAxis 
                          stroke="hsl(var(--muted-foreground))"
                          tick={{ fill: 'hsl(var(--muted-foreground))' }}
                        />
                        <Tooltip 
                          contentStyle={{ 
                            backgroundColor: 'hsl(var(--card))', 
                            border: '1px solid hsl(var(--border))',
                            borderRadius: '8px'
                          }}
                          formatter={(value: any) => `R$ ${Number(value).toFixed(2)}`}
                        />
                        <Legend />
                        <Line 
                          type="monotone" 
                          dataKey="profit" 
                          name="Lucro"
                          stroke="hsl(var(--chart-2))" 
                          strokeWidth={2}
                          dot={{ fill: 'hsl(var(--chart-2))' }}
                        />
                      </LineChart>
                    </ResponsiveContainer>
                  </CardContent>
                </Card>
              </div>

              {/* New Users Chart */}
              <Card className="mb-6">
                <CardHeader>
                  <CardTitle className="text-base font-medium">Novos Usuários por Dia</CardTitle>
                </CardHeader>
                <CardContent>
                  <ResponsiveContainer width="100%" height={300}>
                    <BarChart data={chartData || []}>
                      <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                      <XAxis 
                        dataKey="date" 
                        stroke="hsl(var(--muted-foreground))"
                        tick={{ fill: 'hsl(var(--muted-foreground))' }}
                      />
                      <YAxis 
                        stroke="hsl(var(--muted-foreground))"
                        tick={{ fill: 'hsl(var(--muted-foreground))' }}
                      />
                      <Tooltip 
                        contentStyle={{ 
                          backgroundColor: 'hsl(var(--card))', 
                          border: '1px solid hsl(var(--border))',
                          borderRadius: '8px'
                        }}
                        formatter={(value: any) => `${value} usuários`}
                      />
                      <Legend />
                      <Bar 
                        dataKey="newUsers" 
                        name="Novos Usuários"
                        fill="hsl(var(--chart-1))" 
                        radius={[8, 8, 0, 0]}
                      />
                    </BarChart>
                  </ResponsiveContainer>
                </CardContent>
              </Card>
            </>
          )}

          {activeSection === 'users' && <UsersManagement />}
          {activeSection === 'affiliates' && <AffiliatesManagement />}
          {activeSection === 'deposits' && <TransactionsManagement />}
          {activeSection === 'withdrawals' && <WithdrawalsManagement />}
          {activeSection === 'roulette' && <RouletteSettings />}
          {activeSection === 'general-settings' && <GeneralSettings />}
        </div>
      </main>
    </div>
  );
}

