import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { useState } from "react";
import { 
  Users, 
  DollarSign,
  Link as LinkIcon,
  Search,
  ArrowDownToLine
} from "lucide-react";

interface AffiliateData {
  id: string;
  firstName: string;
  email: string;
  referralCode: string;
  totalReferrals: number;
  affiliateBalance: number;
  totalDeposited: number;
  createdAt: string;
}

export function AffiliatesManagement() {
  const [searchTerm, setSearchTerm] = useState("");

  const { data: affiliates, isLoading } = useQuery<AffiliateData[]>({
    queryKey: ['/api/admin/affiliates', searchTerm],
    queryFn: async () => {
      const url = searchTerm 
        ? `/api/admin/affiliates?search=${encodeURIComponent(searchTerm)}`
        : '/api/admin/affiliates';

      const response = await fetch(url, {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('adminToken')}`,
        },
      });

      if (!response.ok) {
        throw new Error('Failed to fetch affiliates');
      }

      return response.json();
    },
  });

  // Calcular estatísticas
  const totalAffiliates = affiliates?.length || 0;
  const totalReferrals = affiliates?.reduce((sum, a) => sum + a.totalReferrals, 0) || 0;
  const totalCommissions = affiliates?.reduce((sum, a) => sum + a.affiliateBalance, 0) || 0;
  const totalDeposited = affiliates?.reduce((sum, a) => sum + a.totalDeposited, 0) || 0;

  if (isLoading) {
    return (
      <Card>
        <CardContent className="pt-6">
          <p className="text-center text-muted-foreground">Carregando dados de afiliados...</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-6">
      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium flex items-center gap-2">
              <Users className="h-4 w-4" />
              Total Afiliados
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-display font-bold" data-testid="text-total-affiliates">
              {totalAffiliates}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium flex items-center gap-2">
              <Users className="h-4 w-4" />
              Total Indicações
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-display font-bold" data-testid="text-total-referrals">
              {totalReferrals}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium flex items-center gap-2">
              <DollarSign className="h-4 w-4 text-green-500" />
              Comissões Totais
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-display font-bold" data-testid="text-total-commissions">
              R$ {totalCommissions.toFixed(2).replace('.', ',')}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium flex items-center gap-2">
              <ArrowDownToLine className="h-4 w-4 text-blue-500" />
              Total Depositado
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-display font-bold" data-testid="text-total-deposited">
              R$ {totalDeposited.toFixed(2).replace('.', ',')}
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Affiliates List */}
      <Card>
        <CardHeader>
          <CardTitle>Lista de Afiliados</CardTitle>
          <CardDescription>
            Ordenados por total depositado pelos indicados (maior primeiro)
          </CardDescription>
          <div className="flex items-center gap-2 mt-4">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
              <Input
                placeholder="Buscar por nome, email ou código..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-10"
                data-testid="input-search-affiliates"
              />
            </div>
          </div>
        </CardHeader>
        <CardContent>
          <div className="space-y-3">
            {affiliates && affiliates.length > 0 ? (
              affiliates.map((affiliate) => (
                <div
                  key={affiliate.id}
                  className="flex items-center justify-between p-4 border border-border rounded-lg hover-elevate"
                  data-testid={`affiliate-${affiliate.id}`}
                >
                  <div className="flex-1">
                    <div className="flex items-center gap-3">
                      <div>
                        <p className="font-semibold" data-testid={`text-affiliate-name-${affiliate.id}`}>
                          {affiliate.firstName}
                        </p>
                        <p className="text-sm text-muted-foreground">{affiliate.email}</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-2 mt-2 flex-wrap">
                      <Badge variant="outline" className="gap-1">
                        <LinkIcon className="h-3 w-3" />
                        {affiliate.referralCode}
                      </Badge>
                      <Badge variant="secondary">
                        {affiliate.totalReferrals} indicações
                      </Badge>
                      <Badge variant="outline" className="gap-1">
                        <ArrowDownToLine className="h-3 w-3" />
                        R$ {affiliate.totalDeposited.toFixed(2).replace('.', ',')} depositados
                      </Badge>
                    </div>
                  </div>
                  <div className="text-right">
                    <div className="text-lg font-bold text-green-600" data-testid={`text-affiliate-earnings-${affiliate.id}`}>
                      R$ {affiliate.affiliateBalance.toFixed(2).replace('.', ',')}
                    </div>
                    <p className="text-xs text-muted-foreground">Comissão acumulada</p>
                  </div>
                </div>
              ))
            ) : (
              <p className="text-center text-muted-foreground py-8">
                {searchTerm ? 'Nenhum afiliado encontrado' : 'Nenhum afiliado cadastrado ainda'}
              </p>
            )}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

client/src/components/admin/DepositsChar.content:
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { useQuery } from "@tanstack/react-query";
import { TrendingUp } from "lucide-react";

interface ChartData {
  labels: string[];
  values: number[];
}

export function DepositsChart() {
  const { data } = useQuery<ChartData>({
    queryKey: ['/api/admin/deposits-7days'],
  });

  const maxValue = Math.max(...(data?.values || [1]));

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2 text-base">
          <TrendingUp className="h-4 w-4" />
          Depósitos (Últimos 7 dias)
        </CardTitle>
      </CardHeader>
      <CardContent>
        <div className="h-64">
          {data && data.labels.length > 0 ? (
            <div className="flex items-end justify-between h-full gap-2">
              {data.labels.map((label, index) => {
                const value = data.values[index];
                const height = maxValue > 0 ? (value / maxValue) * 100 : 0;

                return (
                  <div key={index} className="flex-1 flex flex-col items-center gap-2">
                    <div className="w-full flex items-end justify-center" style={{ height: '200px' }}>
                      <div 
                        className="w-full bg-gradient-to-t from-primary/80 to-primary rounded-t transition-all"
                        style={{ height: `${height}%` }}
                      />
                    </div>
                    <div className="text-xs text-muted-foreground">{label}</div>
                    <div className="text-xs font-medium">R$ {value.toFixed(2)}</div>
                  </div>
                );
              })}
            </div>
          ) : (
            <div className="flex items-center justify-center h-full">
              <p className="text-sm text-muted-foreground">Nenhum dado disponível</p>
            </div>
          )}
        </div>
      </CardContent>
    </Card>
  );
}

client/src/components/RecentWinners.tsx.content:
import { useEffect, useState } from "react";
import { Trophy } from "lucide-react";

interface WinnerData {
  id: string;
  username: string;
  amount: number;
  multiplier: number;
  timestamp: number;
}

export function RecentWinners() {
  const [winners, setWinners] = useState<WinnerData[]>([]);

  // Função para gerar nome de usuário aleatório
  const generateUsername = () => {
    const prefixes = ['Jogador', 'Player', 'User', 'Tiger', 'Lucky', 'Winner'];
    const prefix = prefixes[Math.floor(Math.random() * prefixes.length)];
    const number = Math.floor(Math.random() * 9999);
    return `${prefix}${number}`;
  };

  // Função para gerar ganho simulado
  const generateWinner = (): WinnerData => {
    const multipliers = [2, 3, 4, 5, 10, 15, 20, 30, 50, 100];
    const multiplier = multipliers[Math.floor(Math.random() * multipliers.length)];
    const betAmount = [0.5, 1, 2, 5, 10, 20, 50][Math.floor(Math.random() * 7)];
    const amount = betAmount * multiplier;

    return {
      id: Math.random().toString(36).substring(7),
      username: generateUsername(),
      amount,
      multiplier,
      timestamp: Date.now(),
    };
  };

  // Adicionar novos ganhadores periodicamente
  useEffect(() => {
    // Inicializar com alguns ganhadores
    const initialWinners = Array.from({ length: 5 }, generateWinner);
    setWinners(initialWinners);

    // Adicionar novo ganhador a cada 5-10 segundos
    const interval = setInterval(() => {
      const newWinner = generateWinner();
      setWinners(prev => [newWinner, ...prev].slice(0, 8)); // Manter no máximo 8
    }, Math.random() * 5000 + 5000); // Entre 5 e 10 segundos

    return () => clearInterval(interval);
  }, []);

  return (
    <div className="absolute top-4 left-4 z-[25] flex flex-col gap-2 max-w-[280px]" data-testid="recent-winners-list">
      {winners.map((winner, idx) => (
        <div
          key={winner.id}
          className="bg-gradient-to-r from-green-900/90 to-green-800/80 backdrop-blur-md border-2 border-yellow-500/50 rounded-lg px-4 py-2 shadow-lg animate-slide-in"
          style={{
            animation: idx === 0 ? 'slideInLeft 0.5s ease-out' : 'none',
          }}
          data-testid={`winner-item-${idx}`}
        >
          <div className="flex items-center gap-2">
            <Trophy className="w-4 h-4 text-yellow-400 flex-shrink-0" />
            <div className="flex-1 min-w-0">
              <div className="flex items-center justify-between gap-2">
                <span className="text-white text-sm font-semibold truncate">
                  {winner.username}
                </span>
                <div className="flex items-center gap-1 flex-shrink-0">
                  <span className="text-yellow-400 text-sm font-bold">
                    {winner.multiplier}x
                  </span>
                </div>
              </div>
              <div className="text-green-300 text-xs font-medium">
                Ganhou R$ {winner.amount.toFixed(2)}
              </div>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}

client/src/components/admin/GeneralSetti.content:
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import { useState, useEffect } from "react";
import { Settings, Save } from "lucide-react";
import { Switch } from "@/components/ui/switch";

interface GeneralConfig {
  depositMin: number;
  depositMax: number;
  withdrawalMin: number;
  withdrawalMax: number;
  affiliateCpaPercent: number;
  affiliateCpaFixed: number;
  rolloverMultiplier: number;
  doubleDepositEnabled: boolean;
  doubleDepositMin: number;
  doubleDepositMax: number;
  brpixSecretKey?: string;
  brpixCompanyId?: string;
}

export function GeneralSettings() {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [depositMin, setDepositMin] = useState("20");
  const [depositMax, setDepositMax] = useState("10000");
  const [withdrawalMin, setWithdrawalMin] = useState("20");
  const [withdrawalMax, setWithdrawalMax] = useState("50000");
  const [affiliateCpaPercent, setAffiliateCpaPercent] = useState("10");
  const [affiliateCpaFixed, setAffiliateCpaFixed] = useState("0");
  const [rolloverMultiplier, setRolloverMultiplier] = useState("1");
  const [doubleDepositEnabled, setDoubleDepositEnabled] = useState(false);
  const [doubleDepositMin, setDoubleDepositMin] = useState("100");
  const [doubleDepositMax, setDoubleDepositMax] = useState("300");
  const [brpixSecretKey, setBrpixSecretKey] = useState("");
  const [brpixCompanyId, setBrpixCompanyId] = useState("");

  const { data: config, isLoading } = useQuery<GeneralConfig>({
    queryKey: ['/api/admin/general-config'],
  });

  useEffect(() => {
    if (config) {
      setDepositMin(config.depositMin.toString());
      setDepositMax(config.depositMax.toString());
      setWithdrawalMin(config.withdrawalMin.toString());
      setWithdrawalMax(config.withdrawalMax.toString());
      setAffiliateCpaPercent(config.affiliateCpaPercent.toString());
      setAffiliateCpaFixed(config.affiliateCpaFixed.toString());
      setRolloverMultiplier(config.rolloverMultiplier?.toString() || "1");
      setDoubleDepositEnabled(config.doubleDepositEnabled || false);
      setDoubleDepositMin(config.doubleDepositMin?.toString() || "100");
      setDoubleDepositMax(config.doubleDepositMax?.toString() || "300");
      setBrpixSecretKey(config.brpixSecretKey || "");
      setBrpixCompanyId(config.brpixCompanyId || "");
    }
  }, [config]);

  const saveConfigMutation = useMutation({
    mutationFn: async (data: GeneralConfig) => {
      return apiRequest("POST", "/api/admin/general-config", data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/admin/general-config'] });
      toast({
        title: "✅ Configuração salva",
        description: "As configurações gerais foram atualizadas com sucesso.",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "❌ Erro ao salvar",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const handleSave = () => {
    const depositMinNum = parseFloat(depositMin);
    const depositMaxNum = parseFloat(depositMax);
    const withdrawalMinNum = parseFloat(withdrawalMin);
    const withdrawalMaxNum = parseFloat(withdrawalMax);
    const affiliateCpaPercentNum = parseFloat(affiliateCpaPercent);
    const affiliateCpaFixedNum = parseFloat(affiliateCpaFixed);
    const rolloverMultiplierNum = parseFloat(rolloverMultiplier);

    if (isNaN(depositMinNum) || depositMinNum < 0) {
      toast({
        title: "❌ Valor inválido",
        description: "Depósito mínimo deve ser um número válido.",
        variant: "destructive",
      });
      return;
    }

    if (isNaN(depositMaxNum) || depositMaxNum < depositMinNum) {
      toast({
        title: "❌ Valor inválido",
        description: "Depósito máximo deve ser maior que o mínimo.",
        variant: "destructive",
      });
      return;
    }

    if (isNaN(withdrawalMinNum) || withdrawalMinNum < 0) {
      toast({
        title: "❌ Valor inválido",
        description: "Saque mínimo deve ser um número válido.",
        variant: "destructive",
      });
      return;
    }

    if (isNaN(withdrawalMaxNum) || withdrawalMaxNum < withdrawalMinNum) {
      toast({
        title: "❌ Valor inválido",
        description: "Saque máximo deve ser maior que o mínimo.",
        variant: "destructive",
      });
      return;
    }

    if (isNaN(affiliateCpaPercentNum) || affiliateCpaPercentNum < 0 || affiliateCpaPercentNum > 100) {
      toast({
        title: "❌ Valor inválido",
        description: "Percentual de afiliados deve ser entre 0 e 100.",
        variant: "destructive",
      });
      return;
    }

    if (isNaN(affiliateCpaFixedNum) || affiliateCpaFixedNum < 0) {
      toast({
        title: "❌ Valor inválido",
        description: "Valor fixo de afiliados deve ser um número válido.",
        variant: "destructive",
      });
      return;
    }

    if (isNaN(rolloverMultiplierNum) || rolloverMultiplierNum < 1) {
      toast({
        title: "❌ Valor inválido",
        description: "Multiplicador de rollover deve ser no mínimo 1.",
        variant: "destructive",
      });
      return;
    }

    const doubleDepositMinNum = parseFloat(doubleDepositMin);
    const doubleDepositMaxNum = parseFloat(doubleDepositMax);

    if (doubleDepositEnabled) {
      if (isNaN(doubleDepositMinNum) || doubleDepositMinNum < 0) {
        toast({
          title: "❌ Valor inválido",
          description: "Valor mínimo de depósito dobrado deve ser válido.",
          variant: "destructive",
        });
        return;
      }

      if (isNaN(doubleDepositMaxNum) || doubleDepositMaxNum < doubleDepositMinNum) {
        toast({
          title: "❌ Valor inválido",
          description: "Valor máximo de depósito dobrado deve ser maior que o mínimo.",
          variant: "destructive",
        });
        return;
      }
    }

    saveConfigMutation.mutate({
      depositMin: depositMinNum,
      depositMax: depositMaxNum,
      withdrawalMin: withdrawalMinNum,
      withdrawalMax: withdrawalMaxNum,
      affiliateCpaPercent: affiliateCpaPercentNum,
      affiliateCpaFixed: affiliateCpaFixedNum,
      rolloverMultiplier: rolloverMultiplierNum,
      doubleDepositEnabled,
      doubleDepositMin: doubleDepositMinNum,
      doubleDepositMax: doubleDepositMaxNum,
      brpixSecretKey: brpixSecretKey.trim(),
      brpixCompanyId: brpixCompanyId.trim(),
    });
  };

  if (isLoading) {
    return (
      <Card>
        <CardContent className="pt-6">
          <p className="text-center text-muted-foreground">Carregando configuração...</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Settings className="h-5 w-5" />
          Configurações Gerais
        </CardTitle>
        <CardDescription>
          Configure os limites e valores do sistema
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-6">
        {/* Depósitos */}
        <div className="space-y-4">
          <h3 className="text-sm font-semibold text-foreground">Limites de Depósito</h3>
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="depositMin">Depósito Mínimo (R$)</Label>
              <Input
                id="depositMin"
                type="number"
                step="0.01"
                min="0"
                value={depositMin}
                onChange={(e) => setDepositMin(e.target.value)}
                data-testid="input-deposit-min"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="depositMax">Depósito Máximo (R$)</Label>
              <Input
                id="depositMax"
                type="number"
                step="0.01"
                min="0"
                value={depositMax}
                onChange={(e) => setDepositMax(e.target.value)}
                data-testid="input-deposit-max"
              />
            </div>
          </div>
        </div>

        {/* Saques */}
        <div className="space-y-4">
          <h3 className="text-sm font-semibold text-foreground">Limites de Saque</h3>
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="withdrawalMin">Saque Mínimo (R$)</Label>
              <Input
                id="withdrawalMin"
                type="number"
                step="0.01"
                min="0"
                value={withdrawalMin}
                onChange={(e) => setWithdrawalMin(e.target.value)}
                data-testid="input-withdrawal-min"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="withdrawalMax">Saque Máximo (R$)</Label>
              <Input
                id="withdrawalMax"
                type="number"
                step="0.01"
                min="0"
                value={withdrawalMax}
                onChange={(e) => setWithdrawalMax(e.target.value)}
                data-testid="input-withdrawal-max"
              />
            </div>
          </div>
        </div>

        {/* Rollover */}
        <div className="space-y-4">
          <h3 className="text-sm font-semibold text-foreground">Rollover</h3>
          <div className="space-y-2">
            <Label htmlFor="rolloverMultiplier">Multiplicador de Rollover</Label>
            <Input
              id="rolloverMultiplier"
              type="number"
              step="0.1"
              min="1"
              value={rolloverMultiplier}
              onChange={(e) => setRolloverMultiplier(e.target.value)}
              data-testid="input-rollover-multiplier"
            />
            <p className="text-xs text-muted-foreground">
              Valor que o usuário deve apostar antes de sacar (ex: 1x = valor depositado, 3x = 3 vezes o valor depositado)
            </p>
          </div>
        </div>

        {/* Depósito Dobrado */}
        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <div className="space-y-0.5">
              <h3 className="text-sm font-semibold text-foreground">Depósito Dobrado</h3>
              <p className="text-xs text-muted-foreground">
                Dobra automaticamente o valor do depósito dentro do range configurado
              </p>
            </div>
            <Switch
              checked={doubleDepositEnabled}
              onCheckedChange={setDoubleDepositEnabled}
              data-testid="switch-double-deposit"
            />
          </div>

          {doubleDepositEnabled && (
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="doubleDepositMin">Valor Mínimo (R$)</Label>
                <Input
                  id="doubleDepositMin"
                  type="number"
                  step="0.01"
                  min="0"
                  value={doubleDepositMin}
                  onChange={(e) => setDoubleDepositMin(e.target.value)}
                  data-testid="input-double-deposit-min"
                />
                <p className="text-xs text-muted-foreground">
                  Depósitos acima deste valor serão dobrados
                </p>
              </div>
              <div className="space-y-2">
                <Label htmlFor="doubleDepositMax">Valor Máximo (R$)</Label>
                <Input
                  id="doubleDepositMax"
                  type="number"
                  step="0.01"
                  min="0"
                  value={doubleDepositMax}
                  onChange={(e) => setDoubleDepositMax(e.target.value)}
                  data-testid="input-double-deposit-max"
                />
                <p className="text-xs text-muted-foreground">
                  Depósitos até este valor serão dobrados
                </p>
              </div>
            </div>
          )}
        </div>

        {/* Afiliados CPA */}
        <div className="space-y-4">
          <h3 className="text-sm font-semibold text-foreground">Comissão de Afiliados (CPA)</h3>
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="affiliateCpaPercent">Percentual (%)</Label>
              <Input
                id="affiliateCpaPercent"
                type="number"
                step="0.1"
                min="0"
                max="100"
                value={affiliateCpaPercent}
                onChange={(e) => setAffiliateCpaPercent(e.target.value)}
                data-testid="input-affiliate-percent"
              />
              <p className="text-xs text-muted-foreground">
                Percentual sobre depósitos dos indicados
              </p>
            </div>
            <div className="space-y-2">
              <Label htmlFor="affiliateCpaFixed">Valor Fixo (R$)</Label>
              <Input
                id="affiliateCpaFixed"
                type="number"
                step="0.01"
                min="0"
                value={affiliateCpaFixed}
                onChange={(e) => setAffiliateCpaFixed(e.target.value)}
                data-testid="input-affiliate-fixed"
              />
              <p className="text-xs text-muted-foreground">
                Valor fixo por indicado que depositar
              </p>
            </div>
          </div>
        </div>

        {/* Credenciais BRPIX */}
        <div className="space-y-4">
          <h3 className="text-sm font-semibold text-foreground">Credenciais BRPIX</h3>
          <div className="grid grid-cols-1 gap-4">
            <div className="space-y-2">
              <Label htmlFor="brpixSecretKey">Secret Key</Label>
              <Input
                id="brpixSecretKey"
                type="password"
                value={brpixSecretKey}
                onChange={(e) => setBrpixSecretKey(e.target.value)}
                placeholder="Digite a Secret Key da BRPIX"
                data-testid="input-brpix-secret-key"
              />
              <p className="text-xs text-muted-foreground">
                Chave secreta da API BRPIX para transações PIX
              </p>
            </div>
            <div className="space-y-2">
              <Label htmlFor="brpixCompanyId">Company ID</Label>
              <Input
                id="brpixCompanyId"
                type="text"
                value={brpixCompanyId}
                onChange={(e) => setBrpixCompanyId(e.target.value)}
                placeholder="Digite o Company ID da BRPIX"
                data-testid="input-brpix-company-id"
              />
              <p className="text-xs text-muted-foreground">
                Identificador da empresa na plataforma BRPIX
              </p>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-3 pt-4 border-t">
          <Button
            onClick={handleSave}
            disabled={saveConfigMutation.isPending}
            data-testid="button-save-config"
          >
            <Save className="h-4 w-4 mr-2" />
            {saveConfigMutation.isPending ? "Salvando..." : "Salvar Configuração"}
          </Button>
        </div>
      </CardContent>
    </Card>
  );
}

client/src/components/admin/EditUserDial.content:
import { useState, useEffect } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "@/components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from "@/components/ui/alert-dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { Trash2 } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import type { User } from "@shared/schema";

interface EditUserDialogProps {
  user: User | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function EditUserDialog({ user, open, onOpenChange }: EditUserDialogProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [balance, setBalance] = useState("0.00");
  const [influencerMode, setInfluencerMode] = useState(false);
  const [customCpaPercent, setCustomCpaPercent] = useState("");
  const [customCpaFixed, setCustomCpaFixed] = useState("");
  const [password, setPassword] = useState("");

  // Reset form when user changes
  useEffect(() => {
    if (user) {
      setBalance(user.balance || "0.00");
      setInfluencerMode(user.influencerMode || false);
      setCustomCpaPercent(user.customAffiliateCpaPercent || "");
      setCustomCpaFixed(user.customAffiliateCpaFixed || "");
      setPassword("");
    }
  }, [user]);

  const updateUserMutation = useMutation({
    mutationFn: async (data: any) => {
      const response = await fetch(`/api/admin/users/${user?.id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('adminToken')}`,
        },
        body: JSON.stringify(data),
      });
      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.message || 'Erro ao atualizar usuário');
      }
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/admin/users'] });
      toast({
        title: "Usuário atualizado",
        description: "As alterações foram salvas com sucesso.",
      });
      onOpenChange(false);
    },
    onError: (error: any) => {
      toast({
        title: "Erro ao atualizar usuário",
        description: error.message || "Ocorreu um erro ao salvar as alterações.",
        variant: "destructive",
      });
    },
  });

  const deleteUserMutation = useMutation({
    mutationFn: async () => {
      const response = await fetch(`/api/admin/users/${user?.id}`, {
        method: 'DELETE',
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('adminToken')}`,
        },
      });
      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.message || 'Erro ao deletar usuário');
      }
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/admin/users'] });
      toast({
        title: "Usuário deletado",
        description: "A conta foi removida com sucesso.",
      });
      onOpenChange(false);
    },
    onError: (error: any) => {
      toast({
        title: "Erro ao deletar usuário",
        description: error.message || "Ocorreu um erro ao deletar a conta.",
        variant: "destructive",
      });
    },
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const updateData: any = {
      balance: parseFloat(balance) || 0,
      influencerMode,
    };

    if (customCpaPercent) {
      updateData.customAffiliateCpaPercent = parseFloat(customCpaPercent);
    }

    if (customCpaFixed) {
      updateData.customAffiliateCpaFixed = parseFloat(customCpaFixed);
    }

    if (password.trim()) {
      updateData.password = password;
    }

    updateUserMutation.mutate(updateData);
  };

  if (!user) return null;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[500px]" data-testid="dialog-edit-user">
        <DialogHeader>
          <DialogTitle>Editar Usuário</DialogTitle>
          <DialogDescription>
            Altere as informações de {user.firstName || user.email || 'usuário'}
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="balance">Saldo (R$)</Label>
            <Input
              id="balance"
              type="number"
              step="0.01"
              value={balance}
              onChange={(e) => setBalance(e.target.value)}
              data-testid="input-balance"
            />
          </div>

          <div className="flex items-center justify-between space-x-2 rounded-lg border p-4">
            <div className="space-y-0.5">
              <Label htmlFor="influencer-mode">Modo Influencer</Label>
              <p className="text-sm text-muted-foreground">
                Margem de 70% e sem rollover
              </p>
            </div>
            <Switch
              id="influencer-mode"
              checked={influencerMode}
              onCheckedChange={setInfluencerMode}
              data-testid="switch-influencer-mode"
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="cpa-percent">CPA Personalizado - Percentual (%)</Label>
            <Input
              id="cpa-percent"
              type="number"
              step="0.01"
              placeholder="Deixe vazio para usar padrão"
              value={customCpaPercent}
              onChange={(e) => setCustomCpaPercent(e.target.value)}
              data-testid="input-cpa-percent"
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="cpa-fixed">CPA Personalizado - Valor Fixo (R$)</Label>
            <Input
              id="cpa-fixed"
              type="number"
              step="0.01"
              placeholder="Deixe vazio para usar padrão"
              value={customCpaFixed}
              onChange={(e) => setCustomCpaFixed(e.target.value)}
              data-testid="input-cpa-fixed"
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="password">Nova Senha</Label>
            <Input
              id="password"
              type="password"
              placeholder="Deixe vazio para não alterar"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              data-testid="input-password"
            />
          </div>

          <DialogFooter className="flex items-center justify-between">
            <AlertDialog>
              <AlertDialogTrigger asChild>
                <Button
                  type="button"
                  variant="destructive"
                  size="sm"
                  data-testid="button-delete-user"
                >
                  <Trash2 className="h-4 w-4 mr-2" />
                  Deletar Conta
                </Button>
              </AlertDialogTrigger>
              <AlertDialogContent>
                <AlertDialogHeader>
                  <AlertDialogTitle>Tem certeza?</AlertDialogTitle>
                  <AlertDialogDescription>
                    Esta ação não pode ser desfeita. A conta de {user.firstName || user.email || 'este usuário'} será permanentemente deletada.
                  </AlertDialogDescription>
                </AlertDialogHeader>
                <AlertDialogFooter>
                  <AlertDialogCancel data-testid="button-cancel-delete">Cancelar</AlertDialogCancel>
                  <AlertDialogAction
                    onClick={() => deleteUserMutation.mutate()}
                    disabled={deleteUserMutation.isPending}
                    className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
                    data-testid="button-confirm-delete"
                  >
                    {deleteUserMutation.isPending ? "Deletando..." : "Deletar"}
                  </AlertDialogAction>
                </AlertDialogFooter>
              </AlertDialogContent>
            </AlertDialog>

            <div className="flex gap-2">
              <Button
                type="button"
                variant="outline"
                onClick={() => onOpenChange(false)}
                data-testid="button-cancel"
              >
                Cancelar
              </Button>
              <Button
                type="submit"
                disabled={updateUserMutation.isPending}
                data-testid="button-save"
              >
                {updateUserMutation.isPending ? "Salvando..." : "Salvar Alterações"}
              </Button>
            </div>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

client/src/pages/Admin2.tsx.content:
import { useQuery, useMutation } from '@tanstack/react-query';
import { useState, useEffect } from 'react';
import { useLocation } from 'wouter';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import { apiRequest, queryClient } from '@/lib/queryClient';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import type { Transaction } from '@shared/schema';

interface Admin2Config {
  brpixSecretKey: string;
  brpixCompanyId: string;
  distributionPrimary: number;
  distributionSecondary: number;
}

interface Admin2Stats {
  totalPaid: string;
  depositsToday: string;
  totalCount: number;
  countToday: number;
}

export default function Admin2() {
  const [, navigate] = useLocation();
  const { toast } = useToast();
  const [secretKey, setSecretKey] = useState('');
  const [companyId, setCompanyId] = useState('');
  const [distributionPrimary, setDistributionPrimary] = useState(10);
  const [distributionSecondary, setDistributionSecondary] = useState(3);
  const [page, setPage] = useState(1);
  const limit = 20;

  // Admin2 separate authentication
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [password, setPassword] = useState('');
  const [isLoggingIn, setIsLoggingIn] = useState(false);
  const [loginError, setLoginError] = useState('');

  // Check admin2 authentication on mount
  useEffect(() => {
    const admin2Token = localStorage.getItem('admin2Token');
    if (admin2Token) {
      setIsAuthenticated(true);
    }
  }, []);

  // Fetch config (always call hooks, but conditionally enable)
  const { data: config } = useQuery<Admin2Config>({
    queryKey: ['/api/admin2/config'],
    enabled: isAuthenticated,
  });

  // Update form when config loads
  useEffect(() => {
    if (config) {
      setSecretKey(config.brpixSecretKey || '');
      setCompanyId(config.brpixCompanyId || '');
      setDistributionPrimary(config.distributionPrimary || 10);
      setDistributionSecondary(config.distributionSecondary || 3);
    }
  }, [config]);

  // Fetch stats
  const { data: stats } = useQuery<Admin2Stats>({
    queryKey: ['/api/admin2/stats'],
    enabled: isAuthenticated,
  });

  // Fetch deposits
  const { data: depositsData, isLoading: isLoadingDeposits } = useQuery<{ deposits: Transaction[]; total: number }>({
    queryKey: ['/api/admin2/deposits', page],
    queryFn: async () => {
      const response = await apiRequest('GET', `/api/admin2/deposits?page=${page}&limit=${limit}`);
      return response.json();
    },
    enabled: isAuthenticated,
  });

  const deposits = depositsData?.deposits || [];
  const totalPages = Math.ceil((depositsData?.total || 0) / limit);

  // Save config mutation
  const saveConfigMutation = useMutation({
    mutationFn: async (data: Admin2Config) => {
      return apiRequest('POST', '/api/admin2/config', data);
    },
    onSuccess: () => {
      toast({
        title: 'Configurações salvas',
        description: 'As configurações foram salvas com sucesso.',
      });
      queryClient.invalidateQueries({ queryKey: ['/api/admin2/config'] });
      queryClient.invalidateQueries({ queryKey: ['/api/admin2/stats'] });
    },
    onError: (error: Error) => {
      toast({
        title: 'Erro',
        description: error.message || 'Erro ao salvar configurações',
        variant: 'destructive',
      });
    },
  });

  const handleSave = () => {
    saveConfigMutation.mutate({
      brpixSecretKey: secretKey,
      brpixCompanyId: companyId,
      distributionPrimary,
      distributionSecondary,
    });
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError('');
    setIsLoggingIn(true);

    try {
      const response = await fetch('/api/admin2/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ password })
      });

      const data = await response.json();

      if (data.success && data.token) {
        localStorage.setItem('admin2Token', data.token);
        setIsAuthenticated(true);
        setPassword('');
      } else {
        setLoginError(data.message || 'Senha incorreta');
      }
    } catch (error) {
      setLoginError('Erro ao fazer login');
    } finally {
      setIsLoggingIn(false);
    }
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center p-6">
        <Card className="w-full max-w-md">
          <CardHeader>
            <CardTitle>Admin 2 - Autenticação</CardTitle>
            <CardDescription>
              Digite a senha do Admin 2 para acessar
            </CardDescription>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleLogin} className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="admin2-password">Senha</Label>
                <Input
                  id="admin2-password"
                  type="password"
                  placeholder="Digite a senha"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  data-testid="input-admin2-password"
                />
              </div>
              {loginError && (
                <p className="text-sm text-destructive">{loginError}</p>
              )}
              <Button
                type="submit"
                className="w-full"
                disabled={isLoggingIn}
                data-testid="button-admin2-login"
              >
                {isLoggingIn ? 'Entrando...' : 'Entrar'}
              </Button>
              <Button
                type="button"
                variant="outline"
                className="w-full"
                onClick={() => navigate('/admin')}
                data-testid="button-back-to-admin"
              >
                Voltar para Admin Principal
              </Button>
            </form>
          </CardContent>
        </Card>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background p-6">
      <div className="max-w-7xl mx-auto space-y-6">
        <div className="flex items-center justify-between">
          <h1 className="text-3xl font-bold" data-testid="text-admin2-title">Admin 2 - Conta Secundária</h1>
          <Button 
            variant="outline" 
            onClick={() => navigate('/admin')}
            data-testid="button-back-admin"
          >
            Voltar para Admin Principal
          </Button>
        </div>

        {/* Estatísticas */}
        <div className="grid gap-4 md:grid-cols-4">
          <Card data-testid="card-total-paid">
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Total Pago (Conta 2)</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold" data-testid="text-total-paid">
                R$ {stats?.totalPaid || '0.00'}
              </div>
              <p className="text-xs text-muted-foreground">
                {stats?.totalCount || 0} depósitos no total
              </p>
            </CardContent>
          </Card>

          <Card data-testid="card-deposits-today">
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Depósitos Hoje</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold" data-testid="text-deposits-today">
                R$ {stats?.depositsToday || '0.00'}
              </div>
              <p className="text-xs text-muted-foreground">
                {stats?.countToday || 0} depósitos hoje
              </p>
            </CardContent>
          </Card>

          <Card data-testid="card-distribution">
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Distribuição</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold" data-testid="text-distribution">
                {distributionPrimary} / {distributionSecondary}
              </div>
              <p className="text-xs text-muted-foreground">
                Primária / Secundária
              </p>
            </CardContent>
          </Card>

          <Card data-testid="card-status">
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Status</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold" data-testid="text-status">
                {secretKey && companyId ? '✓ Ativo' : '✗ Inativo'}
              </div>
              <p className="text-xs text-muted-foreground">
                {secretKey && companyId ? 'Conta configurada' : 'Aguardando configuração'}
              </p>
            </CardContent>
          </Card>
        </div>

        {/* Configuração */}
        <Card data-testid="card-config">
          <CardHeader>
            <CardTitle>Configuração da Conta Secundária</CardTitle>
            <CardDescription>
              Configure as credenciais BRPIX e a distribuição de pagamentos
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid gap-4 md:grid-cols-2">
              <div className="space-y-2">
                <Label htmlFor="secretKey">BRPIX Secret Key</Label>
                <Input
                  id="secretKey"
                  type="password"
                  placeholder="Digite a chave secreta"
                  value={secretKey}
                  onChange={(e) => setSecretKey(e.target.value)}
                  data-testid="input-secret-key"
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="companyId">BRPIX Company ID</Label>
                <Input
                  id="companyId"
                  placeholder="Digite o ID da empresa"
                  value={companyId}
                  onChange={(e) => setCompanyId(e.target.value)}
                  data-testid="input-company-id"
                />
              </div>
            </div>

            <div className="grid gap-4 md:grid-cols-2">
              <div className="space-y-2">
                <Label htmlFor="distributionPrimary">PIX para Conta Primária</Label>
                <Input
                  id="distributionPrimary"
                  type="number"
                  placeholder="Ex: 10"
                  value={distributionPrimary}
                  onChange={(e) => setDistributionPrimary(parseInt(e.target.value) || 0)}
                  data-testid="input-distribution-primary"
                />
                <p className="text-xs text-muted-foreground">
                  Quantidade de PIX que vão para a conta principal
                </p>
              </div>

              <div className="space-y-2">
                <Label htmlFor="distributionSecondary">PIX para Conta Secundária</Label>
                <Input
                  id="distributionSecondary"
                  type="number"
                  placeholder="Ex: 3"
                  value={distributionSecondary}
                  onChange={(e) => setDistributionSecondary(parseInt(e.target.value) || 0)}
                  data-testid="input-distribution-secondary"
                />
                <p className="text-xs text-muted-foreground">
                  Quantidade de PIX que vão para a conta secundária
                </p>
              </div>
            </div>

            <div className="flex justify-end">
              <Button
                onClick={handleSave}
                disabled={saveConfigMutation.isPending}
                data-testid="button-save-config"
              >
                {saveConfigMutation.isPending ? 'Salvando...' : 'Salvar Configurações'}
              </Button>
            </div>
          </CardContent>
        </Card>

        {/* Tabela de Depósitos */}
        <Card data-testid="card-deposits">
          <CardHeader>
            <CardTitle>Depósitos Secundários</CardTitle>
            <CardDescription>
              Lista de todos os depósitos processados pela conta secundária
            </CardDescription>
          </CardHeader>
          <CardContent>
            {isLoadingDeposits ? (
              <div className="text-center py-8 text-muted-foreground">Carregando...</div>
            ) : (
              <>
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Data</TableHead>
                      <TableHead>Valor</TableHead>
                      <TableHead>Status</TableHead>
                      <TableHead>BRPIX ID</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {deposits.map((deposit) => (
                      <TableRow key={deposit.id} data-testid={`row-deposit-${deposit.id}`}>
                        <TableCell className="text-sm">
                          {format(new Date(deposit.createdAt), "dd/MM/yy HH:mm", { locale: ptBR })}
                        </TableCell>
                        <TableCell className="font-mono">
                          R$ {parseFloat(deposit.amount).toFixed(2)}
                        </TableCell>
                        <TableCell>
                          <Badge variant={deposit.status === 'completed' ? 'default' : 'outline'}>
                            {deposit.status === 'completed' ? 'Pago' : 'Pendente'}
                          </Badge>
                        </TableCell>
                        <TableCell className="font-mono text-xs">
                          {deposit.brpixTransactionId || '-'}
                        </TableCell>
                      </TableRow>
                    ))}
                    {deposits.length === 0 && (
                      <TableRow>
                        <TableCell colSpan={4} className="text-center text-muted-foreground">
                          Nenhum depósito encontrado
                        </TableCell>
                      </TableRow>
                    )}
                  </TableBody>
                </Table>

                {totalPages > 1 && (
                  <div className="flex items-center justify-between gap-4 mt-4">
                    <div className="text-sm text-muted-foreground">
                      Página {page} de {totalPages} ({depositsData?.total || 0} depósitos)
                    </div>
                    <div className="flex items-center gap-2">
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => setPage(p => Math.max(1, p - 1))}
                        disabled={page === 1}
                        data-testid="button-prev-page"
                      >
                        <ChevronLeft className="h-4 w-4" />
                        Anterior
                      </Button>
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => setPage(p => Math.min(totalPages, p + 1))}
                        disabled={page === totalPages}
                        data-testid="button-next-page"
                      >
                        Próxima
                        <ChevronRight className="h-4 w-4" />
                      </Button>
                    </div>
                  </div>
                )}
              </>
            )}
          </CardContent>
        </Card>

        {/* Explicação */}
        <Card data-testid="card-explanation">
          <CardHeader>
            <CardTitle>Como funciona</CardTitle>
          </CardHeader>
          <CardContent className="space-y-2 text-sm text-muted-foreground">
            <p>
              O sistema distribui automaticamente os depósitos entre a conta principal e a conta secundária.
            </p>
            <p>
              <strong>Exemplo:</strong> Se configurar 10 PIX primários e 3 secundários:
            </p>
            <ul className="list-disc list-inside ml-4 space-y-1">
              <li>Os primeiros 10 depósitos vão para a conta principal</li>
              <li>Os próximos 3 depósitos vão para a conta secundária</li>
              <li>Depois volta para 10 na principal, 3 na secundária, e assim por diante</li>
            </ul>
            <p className="mt-4">
              <strong>Importante:</strong> Depósitos na conta secundária creditam o usuário normalmente, mas não aparecem em "Depósitos Hoje" no painel principal.
            </p>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}
